import{_ as a,o as t,c as p,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"魔刀千刃","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/魔刀千刃.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/魔刀千刃.md"}'),o={name:"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/魔刀千刃.md"};function d(b,e,l,_,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"魔刀千刃",tabindex:"-1"},[n("魔刀千刃 "),r("a",{class:"header-anchor",href:"#魔刀千刃","aria-label":'Permalink to "魔刀千刃"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘002A")])])],-1),s('<h1 id="魔刀千刃-1" tabindex="-1">魔刀千刃 <a class="header-anchor" href="#魔刀千刃-1" aria-label="Permalink to &quot;魔刀千刃&quot;">​</a></h1><p>魔刀千刃<br> B+2000<br> “只攻不守，天下无双。”</p><p>这柄武器仅余下黑木断柄与紫纹残刃…<br> 特异本质<br> 武器伤害：7L<br> 专业：刀<br> 类型：断刃<br> 体积：2<br> 特性：无</p><p>购买者会立刻回想起自身内心最深处的回忆并处于情绪波动状态，接着该情绪会不可避免的向负面转化，此时购买者需要进行一个意志豁免，DC为自身的决心属性+1。若无法通过，则购买者承受差值的决心属性伤害；如果此时你周围还有其他人，你可能会对他们进行攻击等行为。<br> 每部影片购买者仅能进入一次魔刀千刃所造成的回忆中。<br> 当购买者成功通过意志豁免，则真正获得这柄武器的使用权。</p><p>魔刀千刃<br> 这柄武器由嵌有紫色眼珠的黑木刀柄、三分之一刻有恶鬼纹路的玄色刀身以及三分之二无数碎片合成的刀刃所组成。</p><p>武器伤害：19L<br> 体积：3<br> 专业：刀<br> 分类：刀<br> 特性：破甲3</p><p>这柄武器的刀刃十分容易碎裂，也因此持有者在以其进行格挡时，无法获得格挡所带来的相应好处。</p><p>持有者在一场景内每实际消耗5点内力以此武器进行攻击，则这柄武器的破甲值在本场景内就提高3点，至多提高21点。</p><p>持有者可将自身的内力灌注入这柄武器中，此时刀身的恶鬼纹路会变为蓝色。每轮消耗6点内力，这柄武器的触及范围会在内力的驱动下碎裂延长40米。当你的内力等级提升至A/S级，这柄武器的延长范围会提升至160/360米。</p><p>在一次战斗中，若持有者在魔刀千刃中合计实际消耗了49点内力，则刀身的纹路会化为紫色，此时以魔刀千刃进行的攻击具有A级别措手不及，该措手不及不会无视闪避防御而转为无视目标的格挡防御，在表现上魔刀千刃化为碎片的刀刃绕过了对方用以格挡的武器，而直接对其肉身造成伤害。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',12)])])}const m=a(o,[["render",d]]);export{f as __pageData,m as default};
